import { ORDINAL_DATATYPE } from '../../../core/datatype-constants';
import { ScaleRegistry } from '../../../scale/scale-registry';

export function shapeRangeParser(encodeType, index, config, chart, customMax) {
    // TODO
    let dataSet = chart.dataset,
        dataType = dataSet.getDataType(encodeType),
        { ranges, shapes: userShapes } = config,
        rangeOperators = {};

    if (userShapes) {
        rangeOperators.userShapes = {
            shapes: userShapes
        };
        return rangeOperators;
    }

    rangeOperators.baseShapes = {
        shapes: ['star', 'heart', 'diamond']
    };

    if (ranges || dataType === ORDINAL_DATATYPE) {
        rangeOperators.mapDiscreteDomainToDiscreteRange = { ranges };
    } else {
        rangeOperators.mapContinuousDomainToDiscreteRange = {};
    }

    return rangeOperators;
}

ScaleRegistry.add('shape.rangeParser', shapeRangeParser);
